 25→//// Pooling Functions
 26→
 27→void riscv_nn_avepool_HWC_s8(q7_t * in_tensor,
 28→                             const uint16_t in_tensor_batch,
 29→                             const uint16_t in_tensor_dim,
 30→                             const uint16_t in_tensor_ch,
 31→                             const uint16_t ker_dim,
 32→                             const uint16_t pad,
 33→                             const uint16_t stride,
 34→                             const uint16_t out_tensor_dim,
 35→                             q7_t * in_tmp_buf,
 36→                             q7_t * out_tensor)
 37→{
 38→#ifdef ENA_EMPTY_FUN
 39→    //empty body
 40→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC) && 0
 41→    // the v-ext algorithm is modifed, please remember to update the intrinsic version v-ext algorithm
 42→
 43→    long out_x, out_y, k_x, k_y, in_x, in_y;
 44→
 45→    for (out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
 46→    {
 47→        long ker_y_start = MAX(0, in_y);
 48→        long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
 49→        for (out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
 50→        {
 51→            long count = 0;
 52→            long ker_x_start = MAX(0, in_x);
 53→            long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
 54→            long cur_ch = 0, vl = 0;
 55→
 56→            //calculate the numbers of kernel nodes in the range of input tensor
 57→            for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
 58→            {
 59→                for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
 60→                {
 61→                    count++;
 62→                }
 63→            }
 64→
 65→            long in_tensor_ch2 = in_tensor_ch;
 66→            while(in_tensor_ch2 > 0)
 67→            {
 68→                // reset the accumulators
 69→                vl = __riscv_vsetvl_e16m8(in_tensor_ch2);
 70→                vint16m8_t vAcc_i16 = __riscv_vundefined_i16m8();
 71→                vAcc_i16 = __riscv_vand(vAcc_i16, 0, vl);
 72→                vl = __riscv_vsetvl_e8m4(in_tensor_ch2);
 73→
 74→                for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
 75→                {
 76→                    for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
 77→                    {
 78→                        q7_t *in_ptr = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
 79→                        vint8m4_t vIn_ptr_i8 = __riscv_vle8_v_i8m4(in_ptr, vl);
 80→                        vAcc_i16 = __riscv_vwadd_wv(vAcc_i16, vIn_ptr_i8, vl);
 81→                    }
 82→                }
 83→
 84→                vl = __riscv_vsetvl_e16m8(in_tensor_ch2);
 85→                vAcc_i16 = __riscv_vdiv(vAcc_i16, count, vl);
 86→                vl = __riscv_vsetvl_e8m4(in_tensor_ch2);
 87→                vint8m4_t vResult_i8 = __riscv_vnsra(vAcc_i16, 0, vl);
 88→                __riscv_vse8(out_tensor, vResult_i8, vl);
 89→                out_tensor += vl;
 90→                cur_ch += vl;
 91→                in_tensor_ch2 -= vl;
 92→            }
 93→        }
 94→    }
 95→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ISA_ZVQMAC)
 96→    long cur_batch, out_x, out_y, k_x, k_y, in_x, in_y;
 97→    const long cst_one = 0x1;
 98→    const long input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;
 99→
100→    for (cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
101→    {
102→        for (out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
103→        {
104→            long ker_y_start = MAX(0, in_y);
105→            long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
106→            for (out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
107→            {
108→                long ker_x_start = MAX(0, in_x);
109→                long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
110→                long cur_ch = 0, vl = 0;
111→
112→                if ((ker_y_end > ker_y_start) &&
113→                    (ker_x_end > ker_x_start))
114→                {
115→                    long count = (ker_y_end - ker_y_start) * (ker_x_end - ker_x_start);
116→                    long in_tensor_ch2 = in_tensor_ch;
117→                    while(in_tensor_ch2 > 0)
118→                    {
119→                        // reset the accumulators
120→                        NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
121→                        NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
122→                        NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
123→
124→                        for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
125→                        {
126→                            for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
127→                            {
128→                                q7_t *in_ptr = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
129→                                NDS_VEC_VLE8_V(NDS_VEC_V8, in_ptr);
130→                                NDS_VEC_VQMACC_VX(NDS_VEC_V0, cst_one, NDS_VEC_V8);
131→                            }
132→                        }
133→
134→                        NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
135→                        NDS_VEC_VDIV_VX(NDS_VEC_V0, NDS_VEC_V0, count);
136→                        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
137→                        NDS_VEC_VNSRA_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
138→                        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
139→                        NDS_VEC_VNSRA_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
140→                        NDS_VEC_VSE8_V(NDS_VEC_V0, out_tensor);
141→                        out_tensor += vl;
142→                        cur_ch += vl;
143→                        in_tensor_ch2 -= vl;
144→                    }
145→                }
146→                else
147→                {
148→                    // for those outputs in boundary as there is no overlapping
149→                    // between ifm and kernel
150→                    nn_set_zero_s8(out_tensor, in_tensor_ch);
151→                    out_tensor += in_tensor_ch;
152→                }
153→            }
154→        }
155→        in_tensor += input_len;
156→    }
157→#elif defined(ENA_DSP_ISA_64)
158→    const long input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;
159→    const long_t cst_one_q15x4 = 0x0001000100010001;
160→
161→    for (long cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
162→    {
163→        for (long out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
164→        {
165→            long ker_y_start = MAX(0, in_y);
166→            long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
167→            for (long out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
168→            {
169→                long ker_x_start = MAX(0, in_x);
170→                long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
171→                uint32_t cur_ch;
172→
173→                if ((ker_y_end > ker_y_start) &&
174→                    (ker_x_end > ker_x_start))
175→                {
176→                    long count = (ker_y_end - ker_y_start) * (ker_x_end - ker_x_start);
177→                    for (cur_ch = 0; (cur_ch + SIMD_NUM_Q7) <= in_tensor_ch; cur_ch += SIMD_NUM_Q7)
178→                    {
179→                        suni_t sum_q31x2_0;
180→                        suni_t sum_q31x2_1;
181→                        suni_t sum_q31x2_2;
182→                        suni_t sum_q31x2_3;
183→                        sum_q31x2_0.l0 = 0;
184→                        sum_q31x2_1.l0 = 0;
185→                        sum_q31x2_2.l0 = 0;
186→                        sum_q31x2_3.l0 = 0;
187→
188→                        for (long k_y = ker_y_start; k_y < ker_y_end; k_y++)
189→                        {
190→                            for (long k_x = ker_x_start; k_x < ker_x_end; k_x++)
191→                            {
192→                                q7_t *pIn = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
193→                                suni_t in_q7x8 = simd_load_8(pIn, 0);
194→                                long in_q15x4_0 = NDS_DSP_SUNPKD810(in_q7x8.l0);
195→                                long in_q15x4_1 = NDS_DSP_SUNPKD832(in_q7x8.l0);
196→                                sum_q31x2_0.l0 = NDS_DSP_KMABB(sum_q31x2_0.l0, in_q15x4_0, cst_one_q15x4);
197→                                sum_q31x2_1.l0 = NDS_DSP_KMATT(sum_q31x2_1.l0, in_q15x4_0, cst_one_q15x4);
198→                                sum_q31x2_2.l0 = NDS_DSP_KMABB(sum_q31x2_2.l0, in_q15x4_1, cst_one_q15x4);
199→                                sum_q31x2_3.l0 = NDS_DSP_KMATT(sum_q31x2_3.l0, in_q15x4_1, cst_one_q15x4);
200→                            }
201→                        }
202→
203→                        suni_t out_q7x8;
204→                        out_q7x8.b8.b0 = sum_q31x2_0.b32.w0 / count;
205→                        out_q7x8.b8.b1 = sum_q31x2_1.b32.w0 / count;
206→                        out_q7x8.b8.b2 = sum_q31x2_2.b32.w0 / count;
207→                        out_q7x8.b8.b3 = sum_q31x2_3.b32.w0 / count;
208→                        out_q7x8.b8.b4 = sum_q31x2_0.b32.w1 / count;
209→                        out_q7x8.b8.b5 = sum_q31x2_1.b32.w1 / count;
210→                        out_q7x8.b8.b6 = sum_q31x2_2.b32.w1 / count;
211→                        out_q7x8.b8.b7 = sum_q31x2_3.b32.w1 / count;
212→                        simd_save_8((s8_t*)out_tensor, out_q7x8.l0);
213→                        out_tensor += SIMD_NUM_Q7;
214→                    }
215→
216→                    // rest channels
217→                    for (; cur_ch < in_tensor_ch; cur_ch++)
218→                    {
219→                        int sum = 0;
220→                        for (long k_y = ker_y_start; k_y < ker_y_end; k_y++)
221→                        {
222→                            for (long k_x = ker_x_start; k_x < ker_x_end; k_x++)
223→                            {
224→                                q7_t *pIn = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
225→                                sum += *pIn;
226→                            }
227→                        }
228→
229→                        *out_tensor++ = sum / count;
230→                    }
231→                }
232→                else
233→                {
234→                    // for those outputs in boundary as there is no overlapping
235→                    // between ifm and kernel
236→                    nn_set_zero_s8(out_tensor, in_tensor_ch);
237→                    out_tensor += in_tensor_ch;
238→                }
239→            }
240→        }
241→        in_tensor += input_len;
242→    }
243→#elif defined(ENA_DSP_ISA)
244→    const long input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;
245→
246→    for (long cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
247→    {
248→        for (long out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
249→        {
250→            long ker_y_start = MAX(0, in_y);
251→            long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
252→            for (long out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
253→            {
254→                long ker_x_start = MAX(0, in_x);
255→                long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
256→                uint32_t cur_ch;
257→
258→                if ((ker_y_end > ker_y_start) &&
259→                    (ker_x_end > ker_x_start))
260→                {
261→                    long count = (ker_y_end - ker_y_start) * (ker_x_end - ker_x_start);
262→                    for (cur_ch = 0; (cur_ch + SIMD_NUM_Q7) <= in_tensor_ch; cur_ch += SIMD_NUM_Q7)
263→                    {
264→                        long_t sum_q31_0 = 0;
265→                        long_t sum_q31_1 = 0;
266→                        long_t sum_q31_2 = 0;
267→                        long_t sum_q31_3 = 0;
268→
269→                        for (long k_y = ker_y_start; k_y < ker_y_end; k_y++)
270→                        {
271→                            for (long k_x = ker_x_start; k_x < ker_x_end; k_x++)
272→                            {
273→                                q7_t *pIn = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
274→                                suni_t in_q7x4 = simd_load_8(pIn, 0);
275→                                sum_q31_0 += in_q7x4.b8.b0;
276→                                sum_q31_1 += in_q7x4.b8.b1;
277→                                sum_q31_2 += in_q7x4.b8.b2;
278→                                sum_q31_3 += in_q7x4.b8.b3;
279→                            }
280→                        }
281→
282→                        suni_t out_q7x4;
283→                        out_q7x4.b8.b0 = sum_q31_0 / count;
284→                        out_q7x4.b8.b1 = sum_q31_1 / count;
285→                        out_q7x4.b8.b2 = sum_q31_2 / count;
286→                        out_q7x4.b8.b3 = sum_q31_3 / count;
287→                        simd_save_8((s8_t*)out_tensor, out_q7x4.l0);
288→                        out_tensor += SIMD_NUM_Q7;
289→                    }
290→
291→                    // rest channels
292→                    for (; cur_ch < in_tensor_ch; cur_ch++)
293→                    {
294→                        int sum = 0;
295→                        for (long k_y = ker_y_start; k_y < ker_y_end; k_y++)
296→                        {
297→                            for (long k_x = ker_x_start; k_x < ker_x_end; k_x++)
298→                            {
299→                                q7_t *pIn = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
300→                                sum += *pIn;
301→                            }
302→                        }
303→
304→                        *out_tensor++ = sum / count;
305→                    }
306→                }
307→                else
308→                {
309→                    // for those outputs in boundary as there is no overlapping
310→                    // between ifm and kernel
311→                    nn_set_zero_s8(out_tensor, in_tensor_ch);
312→                    out_tensor += in_tensor_ch;
313→                }
314→            }
315→        }
316→        in_tensor += input_len;
317→    }
318→#else
319→    int16_t   i_batch, i_ch_in, i_x, i_y;
320→    int16_t   k_x, k_y;
321→    const int32_t input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;
322→    const int32_t output_len = out_tensor_dim * out_tensor_dim * in_tensor_ch;
323→
324→    for (i_batch = 0; i_batch < in_tensor_batch; i_batch++)
325→    {
326→        for (i_ch_in = 0; i_ch_in < in_tensor_ch; i_ch_in++)
327→        {
328→            for (i_y = 0; i_y < out_tensor_dim; i_y++)
329→            {
330→                for (i_x = 0; i_x < out_tensor_dim; i_x++)
331→                {
332→                    int       sum = 0;
333→                    int       count = 0;
334→                    for (k_y = i_y * stride - pad; k_y < i_y * stride - pad + ker_dim; k_y++)
335→                    {
336→                        for (k_x = i_x * stride - pad; k_x < i_x * stride - pad + ker_dim; k_x++)
337→                        {
338→                            if (k_y >= 0 && k_x >= 0 && k_y < in_tensor_dim && k_x < in_tensor_dim)
339→                            {
340→                                sum += in_tensor[i_ch_in + in_tensor_ch * (k_x + k_y * in_tensor_dim)];
341→                                count++;
342→                            }
343→                        }
344→                    }
345→
346→                    if (count == 0)
347→                    {
348→                        out_tensor[i_ch_in + in_tensor_ch * (i_x + i_y * out_tensor_dim)] = 0;
349→                    }
350→                    else
351→                    {
352→                        out_tensor[i_ch_in + in_tensor_ch * (i_x + i_y * out_tensor_dim)] = sum / count;
353→                    }
354→                }
355→            }
356→        }
357→        in_tensor += input_len;
358→        out_tensor += output_len;
359→    }
360→#endif
361→}
